6751:     /**
6752:      * An implementation of OnClickListener that attempts to lazily load a
6753:      * named click handling method from a parent or ancestor context.
6754:      */
6755:     private static class DeclaredOnClickListener implements OnClickListener {
6756:         private final View mHostView;
6757:         private final String mMethodName;
6758: 
6759:         private Method mResolvedMethod;
6760:         private Context mResolvedContext;
6761: 
6762:         public DeclaredOnClickListener(@NonNull View hostView, @NonNull String methodName) {
6763:             mHostView = hostView;
6764:             mMethodName = methodName;
6765:         }
6766: 
6767:         @Override
6768:         public void onClick(@NonNull View v) {
6769:             if (mResolvedMethod == null) {
6770:                 resolveMethod(mHostView.getContext(), mMethodName);
6771:             }
6772: 
6773:             try {
6774:                 mResolvedMethod.invoke(mResolvedContext, v);
6775:             } catch (IllegalAccessException e) {
6776:                 throw new IllegalStateException(
6777:                         "Could not execute non-public method for android:onClick", e);
6778:             } catch (InvocationTargetException e) {
6779:                 throw new IllegalStateException(
6780:                         "Could not execute method for android:onClick", e);
6781:             }
6782:         }
6783: 
6784:         @NonNull
6785:         private void resolveMethod(@Nullable Context context, @NonNull String name) {
6786:             while (context != null) {
6787:                 try {
6788:                     if (!context.isRestricted()) {
6789:                         final Method method = context.getClass().getMethod(mMethodName, View.class);
6790:                         if (method != null) {
6791:                             mResolvedMethod = method;
6792:                             mResolvedContext = context;
6793:                             return;
6794:                         }
6795:                     }
6796:                 } catch (NoSuchMethodException e) {
6797:                     // Failed to find method, keep searching up the hierarchy.
6798:                 }
6799: 
6800:                 if (context instanceof ContextWrapper) {
6801:                     context = ((ContextWrapper) context).getBaseContext();
6802:                 } else {
6803:                     // Can't search up the hierarchy, null out and fail.
6804:                     context = null;
6805:                 }
6806:             }
6807: 
6808:             final int id = mHostView.getId();
6809:             final String idText = id == NO_ID ? "" : " with id '"
6810:                     + mHostView.getContext().getResources().getResourceEntryName(id) + "'";
6811:             throw new IllegalStateException("Could not find method " + mMethodName
6812:                     + "(View) in a parent or ancestor Context for android:onClick "
6813:                     + "attribute defined on view " + mHostView.getClass() + idText);
6814:         }
6815:     }
